const express = require('express');
const app = express();
const router = express.Router();
const healthRoutes = require('./modules/health/routes');
const projectRoutes = require('./modules/projects/routes');
const memberRoutes = require('./modules/members/routes');
const taskRoutes = require('./modules/tasks/routes');
const commentRoutes = require('./modules/comments/routes');
app.use(express.json());
router.use('/health', healthRoutes);
router.use('/projects', projectRoutes);
router.use('/projects/:projectId/members', memberRoutes);
router.use('/projects/:projectId/tasks', taskRoutes);
router.use('/projects/:projectId/tasks/:taskId/comments', commentRoutes);
app.use(router);
module.exports = app;

