const express = require('express');
const router = express.Router();
const service = require('./service');
router.post('/', (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Name is required' } });
  const project = service.createProject(req.body);
  res.status(201).json({ project });
});
router.post('/:projectId/members', (req, res) => {
  if (!req.body.userId || !req.body.role) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'UserId and role are required' } });
  const member = service.addMember(req.params.projectId, req.body);
  res.status(201).json({ member });
});
module.exports = router;

const { randomUUID } = require('node:crypto');
const projects = {};
function createProject(data) {
  const id = randomUUID();
  projects[id] = { ...data, id };
  return projects[id];
}
function addMember(projectId, data) {
  if (!projects[projectId]) return null;
  projects[projectId].members = projects[projectId].members || [];
  projects[projectId].members.push({ id: randomUUID(), ...data });
  return projects[projectId].members[projects[projectId].members.length - 1];
}
exports.createProject = createProject;
exports.addMember = addMember;

const express = require('express');
const router = express.Router();
const service = require('./service');
router.post('/:projectId/tasks', (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Name is required' } });
  const task = service.createTask(req.params.projectId, req.body);
  res.status(201).json({ task });
});
router.patch('/:projectId/tasks/:taskId', (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid status' } });
  const task = service.updateTaskStatus(req.params.projectId, req.params.taskId, req.body);
  if (!task) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  res.json({ task });
});
router.get('/:projectId/tasks', (req, res) => {
  const tasks = service.getTasks(req.params.projectId);
  if (!tasks) return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  if (req.query.status === 'done') {
    const doneTasks = tasks.filter(task => task.status === 'done');
    res.json({ tasks: doneTasks });
  } else {
    res.json({ tasks });
  }
});
module.exports = router;

const { randomUUID } = require('node:crypto');
const projects = {};
function createTask(projectId, data) {
  if (!projects[projectId]) return null;
  const id = randomUUID();
  projects[projectId].tasks = projects[projectId].tasks || [];
  projects[projectId].tasks.push({ ...data, id, status: 'todo' });
  return projects[projectId].tasks[projects[projectId].tasks.length - 1];
}
function updateTaskStatus(projectId, taskId, data) {
  if (!projects[projectId]) return null;
  const task = projects[projectId].tasks.find(task => task.id === taskId);
  if (!task) return null;
task.status = data.status;
return task;
}
function getTasks(projectId) {
  if (!projects[projectId]) return null;
  return projects[projectId].tasks || [];
}
exports.createTask = createTask;
exports.updateTaskStatus = updateTaskStatus;
exports.getTasks = getTasks;

