const express = require('express');
const router = express.Router();
const { addMember } = require('./service');
router.post('/', (req, res) => { const member = addMember(req.body); if (!member) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); if (projects.some(p => p.id === req.params.projectId && p.members.includes(member))) return res.status(409).json({ error: { code: 'DUPLICATE_MEMBER', message: 'Member already exists for this project' } }); res.status(201).json(member); });
module.exports = router;

const { randomUUID } = require('crypto');
const addMember = (data) => {
  if (!data.userId || !data.role) return null;
  const member = { id: randomUUID(), ...data };
  return member;
};
module.exports = { addMember };

